        <button id="fix-start">Start Fixed Run</button>
        <button id="fix-reset">Reset</button>
      </div>

      <div class="explain">
        Fix: each task reports its contribution without mutating a shared number directly. Updates are applied through an atomic update function (simple promise-lock here) so the aggregated total is computed deterministically and clamped to 0–100%.
      </div>

      <h3 style="margin-top:12px">Event Log</h3>
      <div class="log" id="fix-log"></div>
    </div>
  </div>

  <footer>
    Click "Start" to run 8 concurrent tasks each contributing random amounts at random times. The buggy version mutates a shared percent (race). The fixed version uses per-task contributions and an atomic updater.
  </footer>

  <script>
    // Utility helpers
    function el(id){ return document.getElementById(id); }
    function logTo(node, msg){
      node.textContent = msg + "\\n" + node.textContent;
    }
    function setBar(barElem, pct){
      const fill = barElem.querySelector('.fill');
      pct = Math.max(0, Math.min(100, Math.round(pct)));
      fill.style.width = pct + '%';
      fill.textContent = pct + '%';
    }

    // Simulated tasks: each resolves after random delay and "reports" an amount
    function simulatedTasks(count){
      const tasks = [];
      for(let i=0;i<count;i++){
        const id = i+1;
        // each promise will resolve at two or three different asynchronous times, to cause more interleaving
        const p = new Promise((resolve) => {
          // schedule a few updates for the same task to simulate progressive work
          const updates = 1 + Math.floor(Math.random()*3); // 1..3 updates
          let contributed = 0;
          function sendUpdate(k){
            // random delay chunk
            const delay = 50 + Math.floor(Math.random()*400);
            setTimeout(() => {
              // contribute some random percent of the total (small chunk)
              const chunk = Math.max(1, Math.floor(Math.random()*15));
              contributed += chunk;
              const done = (k === updates-1);
              resolve({ id, chunk, done, contributed, updates, when: Date.now() });
            }, delay + (k*30)); // slight stagger by k for more interleaving
          }
          // schedule all updates but ensure promise resolves on the first update executed.
          // To force multiple callbacks per task, we expose a function that triggers multiple setTimeouts,
          // but resolve is called for the first of them to reach the handler (simulate concurrency complexity).
          for(let k=0;k<updates;k++) sendUpdate(k);
        });
        tasks.push(p);
      }
      return tasks;
    }

    // A more deterministic simulation that returns per-task multiple events (instead of single resolvable promise)
    // We'll instead create a function that takes a per-task callback to call multiple times asynchronously:
    function runSimulatedTaskEvents(count, perEventCb){
      for(let i=0;i<count;i++){
        const id = i+1;
        const updates = 1 + Math.floor(Math.random()*3); // 1..3 updates per task
        for(let k=0;k<updates;k++){
          const delay = 50 + Math.floor(Math.random()*400) + (k*30);
          (function(id, k, updates){
            setTimeout(() => {
              const chunk = Math.max(1, Math.floor(Math.random()*15)); // contribution chunk percent-ish
              const done = (k === updates-1);
              perEventCb({ id, chunk, done, k, updates, when: Date.now() });
            }, delay);
          })(id,k,updates);
        }
      }
    }

    // BUGGY IMPLEMENTATION:
    (function setupBuggy(){
      const bar = el('bug-bar');
      const log = el('bug-log');
      const start = el('bug-start');
      const reset = el('bug-reset');

      let sharedPercent = 0;
      let running = false;

      function appendLog(msg){
        logTo(log, '[' + new Date().toLocaleTimeString() + '] ' + msg);
      }

      function buggyStart(){
        if(running) { appendLog('Already running'); return; }
        running = true;
        appendLog('Starting buggy run. Shared percent starts at ' + sharedPercent + '%.');

        // Here we intentionally do a non-atomic read-modify-write to sharedPercent:
        runSimulatedTaskEvents(8, (event) => {
          // asynchronous callback: reads sharedPercent, computes new value, writes it back
          // This interleaving can cause races.
          const prior = sharedPercent;
          appendLog('Task ' + event.id + ' reading sharedPercent = ' + prior + ' then will add chunk ' + event.chunk + '. (event k=' + event.k + ')');

          // simulate a small delay between read and write to amplify race
          setTimeout(() => {
            // compute new value based on the (possibly stale) prior
            const newVal = prior + event.chunk;
            sharedPercent = newVal;
            appendLog('Task ' + event.id + ' writing sharedPercent = ' + sharedPercent + ' (wrote ' + event.chunk + ')');

            // update UI (no clamping done intentionally to show >100%)
            setBar(bar, sharedPercent);
          }, Math.random()*120);
        });

        // finalizer: after enough time, mark completion attempt
        setTimeout(() => {
          appendLog('Buggy run finished (no coordination). Final sharedPercent = ' + sharedPercent + '%.');
          running = false;
        }, 2000);
      }

      function buggyReset(){
        sharedPercent = 0;
        setBar(bar, 0);
        log.textContent = '';
        appendLog('Reset sharedPercent to 0%');
      }

      start.addEventListener('click', buggyStart);
      reset.addEventListener('click', buggyReset);
      buggyReset();
    })();

    // FIXED IMPLEMENTATION:
    (function setupFixed(){
      const bar = el('fix-bar');
      const log = el('fix-log');
      const start = el('fix-start');
      const reset = el('fix-reset');

      let totalPercent = 0;
      let running = false;

      function appendLog(msg){
        logTo(log, '[' + new Date().toLocaleTimeString() + '] ' + msg);
      }

      // A simple "mutex" implemented with promises: ensures only one updater runs the critical section at a time.
      // Note: In single-threaded JS this pattern serializes async updates to avoid read-then-write races.
      function createLock(){
        let tail = Promise.resolve();
        return {
          runExclusive: function(fn){
            const myTurn = tail;
            let release;
            tail = new Promise((res) => { release = res; });
            // chain: wait for previous, run, then release
            return myTurn.then(() => {
              try {
                return Promise.resolve(fn());
              } finally {
                release();
              }
            });
          }
        };
      }

      const lock = createLock();

      // Alternative simpler fix: compute contributions separately and accumulate using atomic updater above.
      function fixedStart(){
        if(running) { appendLog('Already running'); return; }
        running = true;
        totalPercent = 0;
        appendLog('Starting fixed run. totalPercent starts at ' + totalPercent + '%.');

        // Each task emits events; instead of reading/writing shared total directly,
        // we submit an update closure to the lock that atomically updates the total.
        runSimulatedTaskEvents(8, (event) => {
          appendLog('Task ' + event.id + ' reports chunk ' + event.chunk + ' (event k=' + event.k + ') — scheduling atomic update');

          // schedule the atomic update using the lock
          lock.runExclusive(() => {
            // this function runs without interleaving with other runExclusive bodies
            const before = totalPercent;
            const after = Math.min(100, before + event.chunk); // clamp to 100
            totalPercent = after;
            appendLog('Atomic update applied: before=' + before + ' + chunk=' + event.chunk + ' => after=' + totalPercent);
            setBar(bar, totalPercent);
          }).catch((err) => {
            appendLog('Error in atomic update: ' + err);
          });
        });

        // finalization
        setTimeout(() => {
          appendLog('Fixed run finished. Final totalPercent = ' + totalPercent + '%.');
          running = false;
        }, 2000);
      }

      function fixedReset(){
        totalPercent = 0;
        setBar(bar, 0);
        log.textContent = '';
        appendLog('Reset totalPercent to 0%');
      }

      start.addEventListener('click', fixedStart);
      reset.addEventListener('click', fixedReset);
      fixedReset();
    })();

    // Extra: allow starting both at once for comparison
    // (not necessary but handy)
  </script>
</body>
