<script>
(function(){
  // Utility: clamp and update UI fill
  function setFill(elFill, elLabel, percent) {
    percent = Math.max(0, Math.min(100, Math.round(percent)));
    elFill.style.width = percent + '%';
    elLabel.textContent = percent + '%';
  }

  // ---------- Buggy implementation ----------
  let buggyControllers = {
    running: false,
    timers: [],
    updateCount: 0,
    internalPercent: 0
  };

  const buggyFill = document.getElementById('buggyFill');
  const buggyLabel = document.getElementById('buggyLabel');
  const buggyStats = document.getElementById('buggyStats');

  document.getElementById('runBuggy').addEventListener('click', () => startBuggy());
  document.getElementById('stopBuggy').addEventListener('click', () => stopBuggy());

  function startBuggy() {
    stopBuggy();
    buggyControllers.running = true;
    buggyControllers.timers = [];
    buggyControllers.updateCount = 0;
    buggyControllers.internalPercent = 0;
    setFill(buggyFill, buggyLabel, 0);
    buggyStats.textContent = 'Updates: 0 • Final internal percent variable: 0';

    const tasks = parseInt(document.getElementById('buggyTasks').value, 10) || 20;
    const maxDelay = parseInt(document.getElementById('buggyMaxDelay').value, 10) || 600;

    // Launch many concurrent tasks that each perform read-modify-write on the shared variable.
    for (let i = 0; i < tasks; i++) {
      // Each task will add a random contribution between 1 and 6 percent.
      const contribution = 1 + Math.floor(Math.random() * 6);
      const delay = 20 + Math.floor(Math.random() * maxDelay);

      const t = setTimeout(() => {
        if (!buggyControllers.running) return;
        // BUG: read-modify-write on shared variable without synchronization
        const readValue = buggyControllers.internalPercent;
        // simulate some asynchronous work taking additional time
        const busyTime = Math.floor(Math.random() * 40);
        // Emulate concurrency by using another setTimeout inside to allow overlaps
        setTimeout(() => {
          if (!buggyControllers.running) return;
          const newValue = readValue + contribution;
          buggyControllers.internalPercent = newValue; // write
          buggyControllers.updateCount++;
          // Update UI based on the shared variable directly
          setFill(buggyFill, buggyLabel, buggyControllers.internalPercent);
          buggyStats.textContent = 'Updates: ' + buggyControllers.updateCount + ' • Final internal percent variable: ' + buggyControllers.internalPercent;
        }, busyTime);
      }, delay);
      buggyControllers.timers.push(t);
    }

    // Safety: after tasks should finish, stop and show final value
    const completionTimer = setTimeout(() => {
      buggyControllers.running = false;
      buggyStats.textContent = 'Updates: ' + buggyControllers.updateCount + ' • Final internal percent variable: ' + buggyControllers.internalPercent + ' (done)';
    }, (maxDelay + 150) + 200);
    buggyControllers.timers.push(completionTimer);
  }

  function stopBuggy() {
    buggyControllers.running = false;
    buggyControllers.timers.forEach(t => clearTimeout(t));
    buggyControllers.timers = [];
  }

  // ---------- Fixed implementation ----------
  // Approach: each task reports its contribution; we aggregate contributions centrally when reported.
  // This avoids the "read-modify-write" race because tasks don't read the shared total,
  // they only send their piece to the aggregator. The aggregator handles each report synchronously.
  let fixedControllers = {
    running: false,
    timers: [],
    updateCount: 0,
    contributions: [], // per-task contributions
    totalContributed: 0
  };

  const fixedFill = document.getElementById('fixedFill');
  const fixedLabel = document.getElementById('fixedLabel');
  const fixedStats = document.getElementById('fixedStats');

  document.getElementById('runFixed').addEventListener('click', () => startFixed());
  document.getElementById('stopFixed').addEventListener('click', () => stopFixed());

  function startFixed() {
    stopFixed();
    fixedControllers.running = true;
    fixedControllers.timers = [];
    fixedControllers.updateCount = 0;
    fixedControllers.contributions = [];
    fixedControllers.totalContributed = 0;
    setFill(fixedFill, fixedLabel, 0);
    fixedStats.textContent = 'Updates: 0 • Total contributed: 0';

    const tasks = parseInt(document.getElementById('fixedTasks').value, 10) || 20;
    const maxDelay = parseInt(document.getElementById('fixedMaxDelay').value, 10) || 600;

    for (let i = 0; i < tasks; i++) {
      const contribution = 1 + Math.floor(Math.random() * 6);
      const delay = 20 + Math.floor(Math.random() * maxDelay);

      const t = setTimeout(() => {
        if (!fixedControllers.running) return;
        // Instead of reading the shared total, the task reports its contribution.
        reportContribution(contribution);
      }, delay);
      fixedControllers.timers.push(t);
    }

    const completionTimer = setTimeout(() => {
      fixedControllers.running = false;
      fixedStats.textContent = 'Updates: ' + fixedControllers.updateCount + ' • Total contributed: ' + fixedControllers.totalContributed + ' (done)';
    }, (maxDelay + 150) + 200);
    fixedControllers.timers.push(completionTimer);
  }

  function stopFixed() {
    fixedControllers.running = false;
    fixedControllers.timers.forEach(t => clearTimeout(t));
    fixedControllers.timers = [];
  }

  function reportContribution(value) {
    // Aggregator runs in the event loop; since JavaScript is single-threaded,
    // this function will execute atomically with respect to other JS callbacks.
    fixedControllers.contributions.push(value);
    fixedControllers.totalContributed += value;
    fixedControllers.updateCount++;
    // clamp to 100 for display but keep totalContributed for stats
    const display = Math.min(100, fixedControllers.totalContributed);
    setFill(fixedFill, fixedLabel, display);
    fixedStats.textContent = 'Updates: ' + fixedControllers.updateCount + ' • Total contributed: ' + fixedControllers.totalContributed;
  }

  // A small utility to demonstrate a serialized update queue (optional)
  // Not used by default UI, but included to show an alternative fix:
  const queueDemo = (function(){
    let q = [];
    let running = false;
    function enqueue(task) {
      q.push(task);
      if (!running) runNext();
    }
    function runNext() {
      if (q.length === 0) { running = false; return; }
      running = true;
      const task = q.shift();
      // run task asynchronously but serialized: schedule via setTimeout(,0)
      setTimeout(() => {
        try { task(); } finally { runNext(); }
      }, 0);
    }
    return { enqueue };
  })();

  // Optional: allow clicking bars to show arrays of contributions for debugging
  buggyFill.addEventListener('click', () => {
    alert('Buggy internal percent: ' + buggyControllers.internalPercent + '\\nUpdates: ' + buggyControllers.updateCount);
  });
  fixedFill.addEventListener('click', () => {
    alert('Fixed total contributed: ' + fixedControllers.totalContributed + '\\nUpdates: ' + fixedControllers.updateCount + '\\nContributions array length: ' + fixedControllers.contributions.length);
  });

  // Initialize displays
  setFill(buggyFill, buggyLabel, 0);
  setFill(fixedFill, fixedLabel, 0);

  // For convenience: run both on load
  // Comment out if you don't want auto-run
  // startBuggy();
  // startFixed();
})();
</script>
