  .bar { height: 100%; background: linear-gradient(90deg,#4caf50,#81c784); width: 0%; transition: width 120ms linear; }
  .label { position: absolute; left: 50%; top: 0; transform: translateX(-50%); height: 100%; display:flex; align-items:center; justify-content:center; font-weight:600; color: #fff; text-shadow: 0 1px 0 rgba(0,0,0,0.3); }
  .controls { margin-top: 10px; display:flex; gap: 8px; }
