<script>
// Utilities
function randInt(min, max){ return Math.floor(Math.random()*(max-min+1))+min; }
function appendLog(el, text){
  const now = new Date().toLocaleTimeString();
  el.textContent = now + "  " + text + "\n" + el.textContent;
}

// ----------------------- BUGGY implementation -----------------------
const buggyBar = document.getElementById('buggyBar');
const buggyLog = document.getElementById('buggyLog');
let buggyProgress = 0; // shared numeric state, mutated directly by tasks

function buggySetBar(pct){
  pct = Math.round(pct);
  buggyBar.style.width = Math.min(pct, 200) + "%"; // intentionally allow >100% visually if p>100
  buggyBar.textContent = pct + "%";
}

function startBuggyTasks(count){
  appendLog(buggyLog, "Starting " + count + " buggy tasks");
  // Each task will wait a random short time, then read and directly update the shared variable.
  for(let i=0;i<count;i++){
    // simulate varying work durations
    const delay = randInt(50, 600);
    setTimeout(() => {
      // simulate a task that increments progress by a random contribution
      const contribution = randInt(5, 25);
      // Important: this is the race-prone sequence:
      // 1) read current progress
      const read = buggyProgress;
      appendLog(buggyLog, `Task ${i} read ${read}%`);
      // 2) do some asynchronous micro-work (simulate with Promise)
      //    interleaving here can cause other tasks to change buggyProgress
      Promise.resolve().then(() => {
        // compute new value based on the stale read
        const newValue = read + contribution;
        appendLog(buggyLog, `Task ${i} computed ${read} + ${contribution} => ${newValue}% and writing`);
        buggyProgress = newValue; // write back, possibly overwriting others' updates
        buggySetBar(buggyProgress);
      });
    }, delay);
  }
}

// controls
document.getElementById('buggyStart').addEventListener('click', () => {
  buggyProgress = 0;
  buggySetBar(0);
  buggyLog.textContent = "";
  startBuggyTasks(6);
});
document.getElementById('buggyMany').addEventListener('click', () => {
  buggyProgress = 0;
  buggySetBar(0);
  buggyLog.textContent = "";
  startBuggyTasks(30);
});
document.getElementById('buggyReset').addEventListener('click', () => {
  buggyProgress = 0;
  buggySetBar(0);
  buggyLog.textContent = "";
});

// ----------------------- FIXED implementation -----------------------
const fixedBar = document.getElementById('fixedBar');
const fixedLog = document.getElementById('fixedLog');
let fixedProgress = 0; // single source of truth, but only updated by the updater
function fixedSetBar(pct){
  pct = Math.round(pct);
  fixedBar.style.width = Math.min(pct,100) + "%"; // cap at 100 visually
  fixedBar.textContent = Math.min(pct,100) + "%";
}

// Approach: Tasks do not mutate the shared counter. Each task returns its
// contribution (or calls a provided reporter). A single updater consumes
// reported contributions and updates the shared state synchronously.
function startFixedTasks(count){
  appendLog(fixedLog, "Starting " + count + " fixed tasks");
  fixedProgress = 0;
  fixedSetBar(0);

  // A queue of contributions to be applied. In real apps, you might not need a queue,
  // but this demonstrates a single updater function that applies contributions atomically.
  const contributionQueue = [];
  let applying = false;

  function reportContribution(taskId, contribution){
    // called by tasks to report what they want to add
    contributionQueue.push({taskId, contribution});
    appendLog(fixedLog, `Task ${taskId} reported +${contribution}%`);
    // drain queue synchronously (no other code will interfere while this runs)
    if(!applying){
      applying = true;
      try {
        while(contributionQueue.length){
          const {taskId, contribution} = contributionQueue.shift();
          fixedProgress += contribution;
          if(fixedProgress > 100) fixedProgress = 100; // enforce cap
          appendLog(fixedLog, `Updater applied Task ${taskId}: +${contribution} => total ${fixedProgress}%`);
          fixedSetBar(fixedProgress);
        }
      } finally {
        applying = false;
      }
    }
  }

  // Launch tasks that will report their contributions instead of mutating the shared var.
  for(let i=0;i<count;i++){
    const delay = randInt(50, 600);
    setTimeout(() => {
      const contribution = randInt(5, 25);
      const read = fixedProgress; // only for logging; not used for updates
      appendLog(fixedLog, `Task ${i} logged local read ${read}% (not used)`);
      // simulate async work, then report contribution
      Promise.resolve().then(() => {
        reportContribution(i, contribution);
      });
    }, delay);
  }
}

// controls
document.getElementById('fixedStart').addEventListener('click', () => {
  fixedProgress = 0;
  fixedSetBar(0);
  fixedLog.textContent = "";
  startFixedTasks(6);
});
document.getElementById('fixedMany').addEventListener('click', () => {
  fixedProgress = 0;
  fixedSetBar(0);
  fixedLog.textContent = "";
  startFixedTasks(30);
});
document.getElementById('fixedReset').addEventListener('click', () => {
  fixedProgress = 0;
  fixedSetBar(0);
  fixedLog.textContent = "";
});
</script>
</body>
