<script>
(function(){
  // DOM refs
  const numTasksEl = document.getElementById('numTasks');
  const unitsEl = document.getElementById('unitsPerTask');
  const maxDelayEl = document.getElementById('maxDelay');
  const runBtn = document.getElementById('runBtn');
  const resetBtn = document.getElementById('resetBtn');
  const fixMethodEl = document.getElementById('fixMethod');

  const bugLog = document.getElementById('bugLog');
  const bugFill = document.getElementById('bugFill');
  const bugPercent = document.getElementById('bugPercent');
  const bugExpected = document.getElementById('bugExpected');
  const bugFinal = document.getElementById('bugFinal');
  const bugStatus = document.getElementById('bugStatus');

  const fixLog = document.getElementById('fixLog');
  const fixFill = document.getElementById('fixFill');
  const fixPercent = document.getElementById('fixPercent');
  const fixExpected = document.getElementById('fixExpected');
  const fixFinal = document.getElementById('fixFinal');
  const fixStatus = document.getElementById('fixStatus');

  const delay = (ms)=> new Promise(r=>setTimeout(r,ms));

  function resetUI(){
    bugLog.textContent = '';
    fixLog.textContent = '';
    bugFill.style.width = '0%';
    fixFill.style.width = '0%';
    bugPercent.textContent = '0%';
    fixPercent.textContent = '0%';
    bugExpected.textContent = '0';
    fixExpected.textContent = '0';
    bugFinal.textContent = '0';
    fixFinal.textContent = '0';
    bugStatus.textContent = 'RUN';
    bugStatus.className = '';
    fixStatus.textContent = 'RUN';
    fixStatus.className = '';
  }

  resetBtn.addEventListener('click', resetUI);
  resetUI();

  runBtn.addEventListener('click', runDemo);

  function appendLog(el, text, cls){
    const line = document.createElement('div');
    if (cls) line.className = cls;
    line.textContent = text;
    el.appendChild(line);
    el.scrollTop = el.scrollHeight;
  }

  function runDemo(){
    resetUI();

    const n = Math.max(1, Math.floor(Number(numTasksEl.value) || 1));
    const units = Math.max(1, Math.floor(Number(unitsEl.value) || 1));
    const maxDelay = Math.max(1, Math.floor(Number(maxDelayEl.value) || 1));
    const expectedTotal = n * units;
    bugExpected.textContent = expectedTotal;
    fixExpected.textContent = expectedTotal;

    // Buggy shared state
    let bugShared = 0;

    // Fixed shared state
    let fixShared = 0;

    // For demonstration, spawn tasks that each "complete" `units` after a random delay.
    // They call reportProgress(units).
    function scheduleTasks(reportFn, logEl, label){
      for (let i=0;i<n;i++){
        const taskId = i+1;
        const d = Math.floor(Math.random()*maxDelay) + 5;
        setTimeout(() => {
          // Simulate some work steps that can interleave
          // We'll intentionally break the operation into read/compute/write with small micro-delays
          // to expose races.
          (async ()=>{
            appendLog(logEl, `[Task ${taskId}] start (delay ${d}ms)`);
            // read
            await delay(0); // yield to allow interleaving
            const observed = reportFn.peek ? reportFn.peek() : undefined;
            appendLog(logEl, `[Task ${taskId}] will add ${units} (observed=${observed})`);
            // compute then write via report function
            await delay(Math.random()*6); // more interleaving
            reportFn(units, taskId);
            appendLog(logEl, `[Task ${taskId}] reported +${units}`);
          })();
        }, d);
      }
    }

    // Buggy report function: read shared, compute, write (no synchronization)
    function bugReport(units, taskId){
      // read
      const old = bugShared;
      // simulate async gap that could have allowed other writes (we already yielded above)
      // compute
      const nw = old + units;
      // write
      bugShared = nw;
      // update UI
      const pct = Math.min(100, Math.round((bugShared / expectedTotal) * 100));
      bugFill.style.width = pct + '%';
      bugPercent.textContent = pct + '%';
    }
    // allow peek for logging
    bugReport.peek = ()=>bugShared;

    // Fixed version - we will implement two different fixes selectable by the dropdown.

    // Fix A: Actor queue (serializes updates by sending increments into an async queue)
    function makeActorReporter(){
      let state = 0;
      const queue = [];
      let running = false;
      function scheduleApply(delta, taskId){
        return new Promise(resolve=>{
          queue.push({delta, taskId, resolve});
          if (!running) drain();
        });
      }
      async function drain(){
        running = true;
        while (queue.length){
          const {delta, taskId, resolve} = queue.shift();
          // apply
          const old = state;
          const nw = old + delta;
          // small async tick to simulate work
          await delay(0);
          state = nw;
          // update UI immediately
          const pct = Math.min(100, Math.round((state / expectedTotal) * 100));
          fixFill.style.width = pct + '%';
          fixPercent.textContent = pct + '%';
          resolve();
        }
        running = false;
      }
      const reporter = async (delta, taskId) => {
        await scheduleApply(delta, taskId);
      };
      reporter.peek = ()=>state;
      // allow reading final state later
      reporter.getState = ()=>state;
      return reporter;
    }

    // Fix B: simple mutex (Promise-based lock)
    function makeMutexReporter(){
      let state = 0;
      let lock = Promise.resolve(); // initially unlocked
      function withLock(fn){
        // chain operations: append to lock, ensure sequential execution
        const next = lock.then(()=>fn());
        // set lock to next, but catch errors to avoid unhandled rejections
        lock = next.catch(()=>{});
        return next;
      }
      const reporter = (delta, taskId) => {
        return withLock(async ()=>{
          const old = state;
          // small yield
          await delay(0);
          state = old + delta;
          const pct = Math.min(100, Math.round((state / expectedTotal) * 100));
          fixFill.style.width = pct + '%';
          fixPercent.textContent = pct + '%';
        });
      };
      reporter.peek = ()=>state;
      reporter.getState = ()=>state;
      return reporter;
    }

    // choose fix
    const fixMethod = fixMethodEl.value;
    let fixReport;
    if (fixMethod === 'actor') fixReport = makeActorReporter();
    else fixReport = makeMutexReporter();

    // schedule tasks for both sides
    scheduleTasks(bugReport, bugLog, 'bug');
    scheduleTasks(fixReport, fixLog, 'fix');

    // After all tasks likely finished, allow a short grace period then show results.
    const overallWait = Math.max(600, Number(maxDelay)*1.2 + 200);
    setTimeout(()=>{
      // finalize
      bugFinal.textContent = bugShared;
      // detect lost updates
      if (bugShared !== expectedTotal){
        bugStatus.textContent = 'BROKEN — lost updates';
        bugStatus.className = 'lost';
      } else {
        bugStatus.textContent = 'OK';
        bugStatus.className = 'ok';
      }

      // fix side
      // if reporter has getState, use it
      const fixState = typeof fixReport.getState === 'function' ? fixReport.getState() : 'unknown';
      fixFinal.textContent = fixState;
      if (fixState !== expectedTotal){
        fixStatus.textContent = 'BROKEN';
        fixStatus.className = 'lost';
      } else {
        fixStatus.textContent = 'OK';
        fixStatus.className = 'ok';
      }

      // add explanation lines
      appendLog(bugLog, `-- expected total: ${expectedTotal}`);
      appendLog(bugLog, `-- observed total: ${bugShared}`);
      appendLog(fixLog, `-- expected total: ${expectedTotal}`);
      appendLog(fixLog, `-- observed total: ${fixState}`);
      // highlight lost updates in bug log by showing the read values that overlapped
      appendLog(bugLog, 'Note: the buggy reporter does "read; compute; write". If two tasks read the same value before either writes, one update is lost.', 'lost');
      appendLog(fixLog, `Fix used: ${fixMethod === 'actor' ? 'Actor (queue)' : 'Mutex (promise lock)'} — updates serialized.`, 'ok');

    }, overallWait);
  }
})();
</script>
