        setTimeout(workerLoop, Math.floor(randRange(0,80)));
      }

      // safety stop after some time
      setTimeout(()=>{ running = false; log(logEl,'[BUGGY] stopped by timer.'); }, 20000);
    }

    function resetAll(){
