  // FIXED implementation using a simple serialized update queue
  (function(){
    const fill = document.getElementById('fixedFill');
    const pct = document.getElementById('fixedPct');
    const start = document.getElementById('fixedStart');
    const reset = document.getElementById('fixedReset');
    const logEl = document.getElementById('fixedLog');

