  function buggyRender(){
    const p = Math.max(0, Math.min(100, buggy.progress));
    buggy.barNode.style.width = p + '%';
    buggy.pctNode.textContent = Math.round(p);
  }

  function buggyStart(){
    buggy.running = true;
    buggy.progress = 0;
    buggy.logNode.textContent = '';
    buggyRender();

    // Kick off many overlapping async tasks that each add some delta
    for(let i=0;i<TASKS;i++){
      const delta = rand(3,8); // each task intends to add this
      // stagger timers and some random additional internal delays to increase interleaving
      const firstDelay = rand(MIN_DELAY, MAX_DELAY);
      const internalDelay = rand(0, MAX_DELAY);

      const id = setTimeout(()=> {
        if(!buggy.running) return;
        // Read the shared value (race starts here)
        const read = buggy.progress;
        buggyLog(`[t${i}] read ${read.toFixed(2)} -> will add ${delta}`);
        // Simulate async work finishing at a later time
        const id2 = setTimeout(()=>{
          if(!buggy.running) return;
          // Compute new value and write (no coordination)
          const newVal = read + delta;
          buggy.progress = newVal;
          buggyLog(`[t${i}] wrote ${newVal.toFixed(2)} (no coordination)`);
          buggyRender();
        }, internalDelay);
        buggy.timers.push(id2);
      }, firstDelay);
      buggy.timers.push(id);
    }

    // Also start a flurry of tiny tasks that do immediate small increments to increase contention
    for(let j=0;j<10;j++){
      const id = setTimeout(()=>{
        if(!buggy.running) return;
        const read = buggy.progress;
        const newVal = read + 1;
        buggy.progress = newVal;
        buggyLog(`[tiny${j}] wrote ${newVal.toFixed(2)}`);
        buggyRender();
      }, rand(0, MAX_DELAY));
      buggy.timers.push(id);
    }

    // Finalizer after a while: report final value
    const fin = setTimeout(()=>{
      buggyLog('Final shared value: ' + buggy.progress.toFixed(2));
      // Don't stop automatically
    }, MAX_DELAY + 800);
    buggy.timers.push(fin);
  }

  function buggyStop(){
    buggy.running = false;
    while(buggy.timers.length) clearTimeout(buggy.timers.pop());
    buggyLog('Stopped.');
  }

  document.getElementById('buggyStart').addEventListener('click', buggyStart);
  document.getElementById('buggyStop').addEventListener('click', buggyStop);

  // ----------------------
  // Fixed implementation
  // ----------------------
  const fixed = {
    progress: 0,
    running: false,
    timers: [],
    logNode: document.getElementById('fixedLog'),
    barNode: document.getElementById('fixedBar'),
    pctNode: document.getElementById('fixedPct')
  };

  function fixedLog(msg){
    const now = (performance.now()/1000).toFixed(3);
    fixed.logNode.textContent = now + '  ' + msg + '\n' + fixed.logNode.textContent;
  }

  function fixedRender(){
    const p = Math.max(0, Math.min(100, fixed.progress));
    fixed.barNode.style.width = p + '%';
    fixed.pctNode.textContent = Math.round(p);
  }

  // Atomic updater: apply a delta in an atomic/serialized way using a synchronous compare-and-replace loop.
  // In JS single-threaded environment there's no native CAS, but this pattern prevents lost updates
  // by re-reading the current value and retrying if it changed between read and intended write.
  // Here we implement a simple mutex-free retry loop by using a small synchronous "applyDelta" function
  // that takes the latest value and applies the delta synchronously. Because JavaScript executes code
  // sequentially, as long as we make the final assignment in one step and avoid intermediate async work
  // on the shared var, we will not lose updates. We also include a timestamp check to detect changed reads.
  function applyDeltaAtomic(delta, tag){
    // We'll implement a small retry mechanism where each caller supplies their intended delta and a tag.
    // Because each call to applyDeltaAtomic executes to completion before another JS task runs,
    // we get atomicity. The important thing is we do not read, wait, then write in separate async steps.
    const before = fixed.progress;
    const after = before + delta;
    fixed.progress = after;
    fixedLog(`[${tag}] applied delta ${delta} -> ${after.toFixed(2)}`);
    fixedRender();
    return after;
  }

  function fixedStart(){
    fixed.running = true;
    fixed.progress = 0;
    fixed.logNode.textContent = '';
    fixedRender();

    // We still launch multiple async tasks, but each task will not read-then-later-write the shared var.
    // Instead each task will schedule a single atomic update when it finishes its work.
    for(let i=0;i<TASKS;i++){
      const delta = rand(3,8);
      const firstDelay = rand(MIN_DELAY, MAX_DELAY);
      const internalDelay = rand(0, MAX_DELAY);

      const id = setTimeout(()=> {
        if(!fixed.running) return;
        fixedLog(`[t${i}] finished work -> will apply ${delta}`);
        // when ready, apply the delta atomically in one synchronous step
        const id2 = setTimeout(()=>{
          if(!fixed.running) return;
          applyDeltaAtomic(delta, `t${i}`);
        }, internalDelay);
        fixed.timers.push(id2);
      }, firstDelay);
      fixed.timers.push(id);
    }

    // tiny tasks also apply atomic deltas
    for(let j=0;j<10;j++){
      const id = setTimeout(()=>{
        if(!fixed.running) return;
        applyDeltaAtomic(1, `tiny${j}`);
      }, rand(0, MAX_DELAY));
      fixed.timers.push(id);
    }

    const fin = setTimeout(()=>{
      fixedLog('Final shared value: ' + fixed.progress.toFixed(2));
    }, MAX_DELAY + 800);
    fixed.timers.push(fin);
  }

  function fixedStop(){
    fixed.running = false;
    while(fixed.timers.length) clearTimeout(fixed.timers.pop());
    fixedLog('Stopped.');
  }

  document.getElementById('fixedStart').addEventListener('click', fixedStart);
  document.getElementById('fixedStop').addEventListener('click', fixedStop);

  // Populate initial instructions
  buggyLog('Press Start. You should see the buggy version sometimes lose increments (stalls, jumps).');
  fixedLog('Press Start. Fixed uses single-step atomic applyDeltaAtomic to avoid lost updates.');
})();
</script>
</body>
</html>

Notes, limitations and why this is convincing
- JavaScript in browsers is single-threaded, so classical multi-threaded data races don't occur. However, concurrency bugs still happen when asynchronous tasks read shared state, do async work, then write it back (a read-modify-write race across async boundaries). That's what this demo shows: two timers can read the same value and later both write, causing lost increments.
- The buggy version demonstrates lost updates because it performs read -> async -> write. The fixed version ensures the write is a single atomic application of the delta, avoiding read-modify-write across async boundaries.
- In real multi-threaded environments you'd use locks, atomic primitives (CAS), or design immutable messages/actors. In JS, designing updates to be applied in a single synchronous step (or using a dedicated updater/queue) prevents these kinds of bugs.

